// Parse le JSON produit par weekly-report.py
const stdout = $input.item.json.stdout || '';
let report = {};
try {
  report = JSON.parse(stdout);
} catch(e) {
  // ES vide ou erreur : rapport avec zéros
  report = {
    period: { from: 'N/A', to: 'N/A' },
    generated_at: new Date().toISOString(),
    total_alerts: 0,
    by_engine: { zeek: 0, snort: 0, suricata: 0 },
    top_rules: [],
    top_src_ips: [],
    severity: { critical: 0, high: 0, medium: 0, low: 0 },
    mitre_ttps: []
  };
}

// Calcul de la semaine ISO
const now = new Date();
const startOfYear = new Date(now.getFullYear(), 0, 1);
const weekNum = Math.ceil(((now - startOfYear) / 86400000 + startOfYear.getDay() + 1) / 7);
const isoWeek = `${now.getFullYear()}-W${String(weekNum).padStart(2, '0')}`;

// Prépare les chiffres clés pour la carte Teams
const topRules = (report.top_rules || []).slice(0, 3);
const byEngine = report.by_engine || {};
const severity = report.severity || {};
const periodFrom = (report.period || {}).from || 'N/A';
const periodTo = (report.period || {}).to || 'N/A';

return [{ json: { report, isoWeek, topRules, byEngine, severity, periodFrom, periodTo } }];

// Construit l'Adaptive Card Teams pour le rapport hebdomadaire
const { report, isoWeek, topRules, byEngine, severity, periodFrom, periodTo } = $input.item.json;
const portalUrl = 'http://localhost:5050';
const total = report.total_alerts || 0;

// Lignes top 3 règles
const rulesFacts = topRules.length > 0
  ? topRules.map((r, i) => ({
      title: `#${i + 1}`,
      value: `${String(r.name || 'N/A').substring(0, 70)} (${r.count})`
    }))
  : [{ title: 'Top règles', value: 'Aucune alerte cette semaine' }];

// Couleur titre selon volume
const titleColor = total === 0 ? 'Good' : total < 100 ? 'Warning' : 'Attention';

const payload = {
  type: 'message',
  attachments: [
    {
      contentType: 'application/vnd.microsoft.card.adaptive',
      content: {
        '$schema': 'http://adaptivecards.io/schemas/adaptive-card.json',
        type: 'AdaptiveCard',
        version: '1.4',
        body: [
          {
            type: 'TextBlock',
            text: `NetWatch — Rapport Hebdomadaire ${isoWeek}`,
            weight: 'Bolder',
            size: 'Large',
            color: titleColor,
            wrap: true
          },
          {
            type: 'TextBlock',
            text: `Période : ${periodFrom} → ${periodTo}`,
            size: 'Small',
            isSubtle: true,
            wrap: true
          },
          {
            type: 'ColumnSet',
            columns: [
              {
                type: 'Column',
                width: 'stretch',
                items: [
                  {
                    type: 'TextBlock',
                    text: 'Alertes totales',
                    weight: 'Bolder',
                    size: 'Small'
                  },
                  {
                    type: 'TextBlock',
                    text: String(total),
                    size: 'ExtraLarge',
                    weight: 'Bolder',
                    color: titleColor
                  }
                ]
              },
              {
                type: 'Column',
                width: 'stretch',
                items: [
                  {
                    type: 'TextBlock',
                    text: 'Par moteur',
                    weight: 'Bolder',
                    size: 'Small'
                  },
                  {
                    type: 'FactSet',
                    facts: [
                      { title: 'Zeek', value: String(byEngine.zeek || 0) },
                      { title: 'Snort', value: String(byEngine.snort || 0) },
                      { title: 'Suricata', value: String(byEngine.suricata || 0) }
                    ]
                  }
                ]
              },
              {
                type: 'Column',
                width: 'stretch',
                items: [
                  {
                    type: 'TextBlock',
                    text: 'Par sévérité',
                    weight: 'Bolder',
                    size: 'Small'
                  },
                  {
                    type: 'FactSet',
                    facts: [
                      { title: 'Critical', value: String(severity.critical || 0) },
                      { title: 'High', value: String(severity.high || 0) },
                      { title: 'Medium', value: String(severity.medium || 0) },
                      { title: 'Low', value: String(severity.low || 0) }
                    ]
                  }
                ]
              }
            ]
          },
          {
            type: 'TextBlock',
            text: 'Top 3 règles déclenchées',
            weight: 'Bolder',
            size: 'Medium',
            separator: true
          },
          {
            type: 'FactSet',
            facts: rulesFacts
          }
        ],
        actions: [
          {
            type: 'Action.OpenUrl',
            title: 'Ouvrir le portail NetWatch',
            url: portalUrl
          }
        ]
      }
    }
  ]
};

return [{ json: payload }];
